mapper.insert:
INSERT INTO CMN_PSC_NOTICE_MST 
(
	NOTICE_ID
	,TITLE
	,CONTENTS
	,DELETE_YN
	,POST_STRT_DT
	,POST_END_DT
	,REGST_ID
	,REGST_DTTM
	,ORGN10
	,REGST_ORGN_NM
	,REGST_USR_NM
	,P_NOTICE_ID
)
VALUES
(
	#{NOTICE_ID}
	,#{TITLE}
	,#{CONTENTS}
	,NVL( #{DELETE_YN}, 'N')
	,#{POST_STRT_DT}
	,#{POST_STRT_DT}
	,#{SESSION_USER_ID }
	,SYSDATE
	,1
	,( SELECT A.ORGN_NM 
	  FROM ORG_ORGN_INFO_MST A
		  ,CMN_USR_MST B
	  WHERE 1=1
	   AND A.ORGN_ID = B.ORGN_ID
	   AND B.USR_ID = #{SESSION_USER_ID}
	  )
	,(SELECT USR_NM FROM CMN_USR_MST WHERE USR_ID = #{SESSION_USER_ID})
	,#{P_NOTICE_ID}
)

mapper.update:
UPDATE CMN_PSC_NOTICE_MST
SET 
	TITLE				=  #{TITLE}
	,CONTENTS		= #{CONTENTS}
	,POST_STRT_DT  = #{POST_STRT_DT}
	,POST_END_DT   = #{POST_STRT_DT}
	,RVISN_ID			= #{SESSION_USER_ID}
	,RVISN_DTTM	= SYSDATE
	,RVISN_ORGN_NM = ( SELECT A.ORGN_NM 
								FROM ORG_ORGN_INFO_MST A ,CMN_USR_MST B WHERE 1=1
								   AND A.ORGN_ID = B.ORGN_ID
								   AND B.USR_ID = #{SESSION_USER_ID}
								)
	,RVISN_USR_NM = (SELECT USR_NM FROM CMN_USR_MST WHERE USR_ID = #{SESSION_USER_ID})
WHERE NOTICE_ID = #{NOTICE_ID}

UPDATE CMN_PSC_NOTICE_MST
SET    DELETE_YN = 'Y'
	  ,RVISN_ID			= #{SESSION_USER_ID}
	  ,RVISN_DTTM	= SYSDATE
	  ,RVISN_ORGN_NM = ( SELECT A.ORGN_NM 
						   FROM ORG_ORGN_INFO_MST A ,CMN_USR_MST B WHERE 1=1
							AND A.ORGN_ID = B.ORGN_ID
							AND B.USR_ID = #{SESSION_USER_ID}
						)
	  ,RVISN_USR_NM = (SELECT USR_NM FROM CMN_USR_MST WHERE USR_ID = #{SESSION_USER_ID})
WHERE NOTICE_ID = #{NOTICE_ID}

